//
//  Rob8View.swift
//  Polly
//
//  Uses the real Rob8 SVG illustration.
//  Currently the same SVG is used for all moods (default/happy).
//  Other mood SVGs will be added progressively by the designer.
//  When a new SVG arrives, just replace the matching `case` in rob8SVG(for:).
//

import SwiftUI

// MARK: - SVG Router

/// Returns the correct SVG string for the given mood.
/// Replace each TODO case as the designer delivers the artwork.
private func rob8SVG(for mood: RobotMood) -> String {
    switch mood {
    case .happy:   return rob8Happy
    case .hungry:  return rob8Hungry
    case .tired:   return rob8Tired
    case .curious: return rob8Curious
    case .bored:   return rob8Bored
    case .chatting: return rob8Chat
    }
}

