// MARK: - Rob8View

struct Rob8View: View {
    let mood: RobotMood
    var size: CGFloat = 120
    var animate: Bool = true

    @State private var bobOffset: CGFloat = 0

    /// Parse width/height from the SVG's viewBox attribute so each mood
    /// uses its own correct aspect ratio (chatting has wider headphones).
    private var aspectRatio: CGFloat {
        let svg = rob8SVG(for: mood)
        if let range = svg.range(of: #"viewBox="0 0 ([\d.]+) ([\d.]+)""#,
                                  options: .regularExpression),
           let wRange = svg[range].range(of: #"(?<=0 )([\d.]+)(?= [\d.]+")"#,
                                          options: .regularExpression) {
            let w = CGFloat(Double(svg[wRange]) ?? 219.11)
            return w / 470.3
        }
        return 219.11 / 470.3
    }

    private var svgWidth:  CGFloat { size * aspectRatio }
    private var svgHeight: CGFloat { size }

    var body: some View {
        SVGWebView(svg: rob8SVG(for: mood))
            .frame(width: svgWidth, height: svgHeight)
            .offset(y: bobOffset)
            .onAppear {
                guard animate else { return }
                withAnimation(
                    .easeInOut(duration: 1.6)
                    .repeatForever(autoreverses: true)
                ) {
                    bobOffset = -6
                }
            }
    }
}

// MARK: - Preview

#Preview {
    HStack(spacing: 20) {
        ForEach([RobotMood.happy, .hungry, .chatting, .curious, .bored, .tired], id: \.self) { mood in
            VStack(spacing: 8) {
                Rob8View(mood: mood, size: 100, animate: false)
                Text("\(mood)")
                    .font(.system(size: 10, design: .monospaced))
                    .foregroundColor(.gray)
            }
        }
    }
    .padding(24)
    .background(Color(red: 0.10, green: 0.10, blue: 0.09))
}
